import 'dart:convert'; import 'package:flutter_secure_storage/flutter_secure_storage.dart'; import 'package:injectable/injectable.dart'; import '../model/auth_user.dart'; @singleton class SessionCache { final FlutterSecureStorage _storage; static const _key = 'auth_session_v1'; SessionCache(this._storage); Future<void> save(AuthUser u) => _storage.write(key: _key, value: jsonEncode(u.toJson())); Future<AuthUser?> load() async { final r = await _storage.read(key: _key); if (r == null) return null; try { return AuthUser.fromJson(jsonDecode(r)); } catch (_) { return null; } } Future<void> clear() => _storage.delete(key: _key); }